import React, { useState, useEffect, useCallback } from 'react';
import {
  View,
  Text,
  Button,
  TextInput,
  StyleSheet,
  Alert,
  ActivityIndicator,
  Platform,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics, { Biometrics } from 'react-native-biometrics';

// --- Constants ---
const AUTHENTICATED_KEY = 'isAuthenticated';
const CORRECT_PASSWORD = 'testpassword'; // For password fallback

// --- HomeScreen Component ---
const HomeScreen = ({ onLogout }) => {
  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome Home!</Text>
      <Text style={styles.subtitle}>You are successfully authenticated.</Text>
      <Button title="Logout" onPress={onLogout} />
    </View>
  );
};

// --- AuthScreen Component ---
const AuthScreen = ({ onAuthSuccess }) => {
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState(null);
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const rnBiometrics = new ReactNativeBiometrics();

  useEffect(() => {
    const checkBiometrics = async () => {
      try {
        const { available, biometryType } = await rnBiometrics.isSensorAvailable();
        if (available) {
          setBiometricsAvailable(true);
          setBiometricType(biometryType);
        } else {
          console.log('Biometrics not available on this device');
          setShowPasswordInput(true); // Fallback to password if no biometrics
        }
      } catch (error) {
        console.error('Error checking biometrics:', error);
        setShowPasswordInput(true); // Fallback on error
      }
    };
    checkBiometrics();
  }, []);

  const storeAuthStatus = async () => {
    try {
      await AsyncStorage.setItem(AUTHENTICATED_KEY, 'true');
      onAuthSuccess();
    } catch (e) {
      console.error('Failed to save authentication status', e);
      Alert.alert('Error', 'Could not save authentication status. Please try again.');
    }
  };

  const handleBiometricAuth = useCallback(async () => {
    setIsLoading(true);
    try {
      const promptMessage = `Confirm your ${
        biometricType === Biometrics.FaceID ? 'Face ID' : 'fingerprint'
      } to log in`;
      const { success } = await rnBiometrics.simplePrompt({ promptMessage });

      if (success) {
        await storeAuthStatus();
      } else {
        Alert.alert('Authentication Failed', 'Biometric authentication was not successful or was cancelled.');
        setShowPasswordInput(true); // Offer password fallback if biometrics fails/cancels
      }
    } catch (error) {
      console.error('Biometric authentication error:', error);
      Alert.alert(
        'Authentication Error',
        'Could not complete biometric authentication. Please try password instead.'
      );
      setShowPasswordInput(true); // Fallback on error
    } finally {
      setIsLoading(false);
    }
  }, [biometricType, storeAuthStatus]);

  const handlePasswordLogin = useCallback(async () => {
    setIsLoading(true);
    if (password === CORRECT_PASSWORD) {
      await storeAuthStatus();
    } else {
      Alert.alert('Login Failed', 'Incorrect password. Please try again.');
    }
    setIsLoading(false);
  }, [password, storeAuthStatus]);

  if (isLoading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#0000ff" />
        <Text>Authenticating...</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>

      {biometricsAvailable && !showPasswordInput && (
        <View style={styles.section}>
          <Text style={styles.subtitle}>
            Use your {biometricType === Biometrics.FaceID ? 'Face ID' : 'fingerprint'}
          </Text>
          <Button
            title={`Login with ${biometricType === Biometrics.FaceID ? 'Face ID' : 'Fingerprint'}`}
            onPress={handleBiometricAuth}
          />
          <Text style={styles.orText}>OR</Text>
          <Button title="Use Password" onPress={() => setShowPasswordInput(true)} />
        </View>
      )}

      {(!biometricsAvailable || showPasswordInput) && (
        <View style={styles.section}>
          <Text style={styles.subtitle}>Enter Password</Text>
          <TextInput
            style={styles.input}
            placeholder="Password"
            secureTextEntry
            value={password}
            onChangeText={setPassword}
          />
          <Button title="Login with Password" onPress={handlePasswordLogin} />
          {biometricsAvailable && showPasswordInput && (
            <Button title="Back to Biometrics" onPress={() => setShowPasswordInput(false)} />
          )}
        </View>
      )}
    </View>
  );
};

// --- Main App Component ---
export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoadingApp, setIsLoadingApp] = useState(true);

  useEffect(() => {
    const checkAuthStatus = async () => {
      try {
        const storedAuthStatus = await AsyncStorage.getItem(AUTHENTICATED_KEY);
        if (storedAuthStatus === 'true') {
          setIsAuthenticated(true);
        }
      } catch (e) {
        console.error('Failed to load authentication status', e);
      } finally {
        setIsLoadingApp(false);
      }
    };
    checkAuthStatus();
  }, []);

  const handleAuthSuccess = useCallback(() => {
    setIsAuthenticated(true);
  }, []);

  const handleLogout = useCallback(async () => {
    try {
      await AsyncStorage.removeItem(AUTHENTICATED_KEY);
      setIsAuthenticated(false);
    } catch (e) {
      console.error('Failed to remove authentication status', e);
      Alert.alert('Error', 'Could not log out. Please try again.');
    }
  }, []);

  if (isLoadingApp) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#0000ff" />
        <Text>Loading app...</Text>
      </View>
    );
  }

  return isAuthenticated ? (
    <HomeScreen onLogout={handleLogout} />
  ) : (
    <AuthScreen onAuthSuccess={handleAuthSuccess} />
  );
}

